{"code":"import json

# Load books
books = locals()['var_function-call-7197889921205200491']
# Load reviews
reviews_path = locals()['var_function-call-7197889921205198904']
with open(reviews_path, 'r') as f:
    reviews = json.load(f)

# Create map of all fetched books (we assume they are Children's Books due to SQL filter)
valid_books = {b['book_id']: b['title'] for b in books}

# Check ID mapping and intersection
mapped_ids = set()
for r in reviews:
    pid = r['purchase_id']
    if pid.startswith('purchaseid_'):
        bid = 'bookid_' + pid.split('_')[1]
        mapped_ids.add(bid)

intersection = set(valid_books.keys()).intersection(mapped_ids)

# Calculate ratings
book_ratings = {}
for r in reviews:
    pid = r['purchase_id']
    if pid.startswith('purchaseid_'):
        bid = 'bookid_' + pid.split('_')[1]
        if bid in valid_books:
            if bid not in book_ratings:
                book_ratings[bid] = []
            book_ratings[bid].append(float(r['rating']))

# Filter >= 4.5
result_titles = []
for bid, ratings in book_ratings.items():
    avg = sum(ratings) / len(ratings)
    if avg >= 4.5:
        result_titles.append(valid_books[bid])

result_titles.sort()

print("__RESULT__:")
print(json.dumps(result_titles))"}

